import React, { useState, useEffect } from 'react';
import { api } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { Trash2, Edit, ExternalLink, PlusCircle, Store } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import ModalNuevaSucursal from './ModalNuevaSucursal';

const Dashboard = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [locales, setLocales] = useState([]);
    const [showModal, setShowModal] = useState(false);
    const [localParaEditar, setLocalParaEditar] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (user?.id) cargarDatos();
    }, [user]);

    const cargarDatos = async () => {
        setLoading(true);
        try {
            const data = await api.getLocalesVendedor(user.id);
            setLocales(data);
        } catch (e) { console.error(e); }
        setLoading(false);
    };

    const handleSave = async (formData) => {
        try {
            if (localParaEditar) {
                await api.actualizarLocal(localParaEditar._id, formData);
            } else {
                await api.crearLocal({ ...formData, vendedorId: user.id });
            }
            setShowModal(false);
            setLocalParaEditar(null);
            cargarDatos();
        } catch (e) { alert("Error al guardar"); }
    };

    const handleEliminar = async (id) => {
        if (window.confirm("¿Eliminar este local? Se borrarán sus ofertas.")) {
            await api.eliminarLocal(id);
            cargarDatos();
        }
    };

    if (loading) return <div style={loaderStyle}>Cargando tus locales...</div>;

    return (
        <div style={containerStyle}>
            <header style={headerStyle}>
                <div>
                    <h1 style={{margin:0}}>Panel de Vendedor</h1>
                    <p style={{color:'#64748b'}}>Gestiona tus sucursales y ofertas</p>
                </div>
                <button onClick={() => { setLocalParaEditar(null); setShowModal(true); }} style={btnPlus}>
                    <PlusCircle size={20} /> Nuevo Local
                </button>
            </header>

            <div style={gridStyle}>
                {locales.map(local => (
                    <div key={local._id} style={cardStyle}>
                        <div style={cardBadge}><Store size={14}/> Sucursal</div>
                        <h3 style={{marginTop: '10px'}}>{local.nombre}</h3>
                        <p style={addressStyle}>📍 {local.direccion}</p>
                        
                        <div style={actionsContainer}>
                            <button onClick={() => navigate(`/ofertas/${local._id}`)} style={btnManage}>
                                <ExternalLink size={16} /> Ver Ofertas
                            </button>
                            <button onClick={() => { setLocalParaEditar(local); setShowModal(true); }} style={btnEdit}>
                                <Edit size={16} />
                            </button>
                            <button onClick={() => handleEliminar(local._id)} style={btnDelete}>
                                <Trash2 size={16} />
                            </button>
                        </div>
                    </div>
                ))}
            </div>

            {showModal && (
                <ModalNuevaSucursal 
                    onClose={() => {setShowModal(false); setLocalParaEditar(null);}} 
                    onSave={handleSave}
                    datosIniciales={localParaEditar}
                />
            )}
        </div>
    );
};

// Estilos avanzados
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '25px' };
const cardStyle = { background: 'white', padding: '24px', borderRadius: '20px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', position: 'relative', border: '1px solid #f1f5f9' };
const cardBadge = { background: '#f1f5f9', color: '#475569', padding: '4px 10px', borderRadius: '20px', fontSize: '12px', fontWeight: 'bold', display: 'inline-flex', alignItems: 'center', gap: '5px' };
const addressStyle = { color: '#64748b', fontSize: '14px', marginBottom: '20px' };
const actionsContainer = { display: 'flex', gap: '10px' };
const btnPlus = { background: '#e67e22', color: 'white', border: 'none', padding: '12px 20px', borderRadius: '12px', cursor: 'pointer', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '8px' };
const btnManage = { flex: 2, background: '#1e293b', color: 'white', border: 'none', borderRadius: '10px', padding: '10px', cursor: 'pointer', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '8px' };
const btnEdit = { flex: 0.5, background: '#f1f5f9', color: '#475569', border: 'none', borderRadius: '10px', padding: '10px', cursor: 'pointer' };
const btnDelete = { flex: 0.5, background: '#fee2e2', color: '#ef4444', border: 'none', borderRadius: '10px', padding: '10px', cursor: 'pointer' };
const loaderStyle = { textAlign: 'center', padding: '100px', fontSize: '1.2rem', color: '#e67e22' };

export default Dashboard;
